def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 15):
            term = (1 / (j**3 + 1)) * (ratio ** j)
            if j % 3 == 0:
                term *= 1.2
            elif j % 2 == 0:
                term *= 0.8
            else:
                term *= 1.0
            score += term
        remaining = capacity - item
        if remaining < 0:
            priorities[i] = np.inf
            continue
        elif remaining < 0.03 * capacity:
            score *= 2.5
        elif remaining < 0.1 * capacity:
            score *= 1.8
        elif remaining < 0.25 * capacity:
            score *= 1.2
        else:
            score *= 0.7
        if int(capacity) % 2 == 0 and int(capacity) % 7 == 0:
            score -= 0.15 * (capacity / 12)
        elif int(capacity) % 4 == 0:
            score -= 0.07 * (capacity / 18)
        else:
            score -= 0.03 * (capacity / 25)
        penalty = 0
        for k in range(1, 6):
            diff = abs(capacity - item * k)
            threshold = 0.01 * capacity + 0.005 * k
            if diff < threshold:
                penalty += 0.25 * k
            if diff < 0.002 * capacity:
                penalty += 0.1 * (6 - k)
        score += penalty
        bonus = 0
        for m in range(1, int(capacity // item) + 1):
            residual = capacity - item * m
            if 0 < residual < 0.05 * capacity:
                bonus += 0.1 / m
        score += bonus
        for n in range(1, 4):
            if (capacity % (item * n)) < 0.02 * capacity:
                score += 0.05 * n
        if score < 0:
            score = 0
        if ratio > 0.95:
            score *= 1.5
        priorities[i] = score
    return priorities
